// Analyze system health
const items = $input.all();
const workflowHealth = items.filter(i => i.json.workflow_id).map(i => i.json);
const dataHealth = items.find(i => i.json.traffic_data !== undefined)?.json || {};

const issues = [];
let overallStatus = 'healthy';

// Check for workflow failures
const failingWorkflows = workflowHealth.filter(w => w.failures_24h > 0);
if (failingWorkflows.length > 0) {
  overallStatus = 'degraded';
  failingWorkflows.forEach(w => {
    issues.push({
      type: 'workflow_failure',
      severity: w.failures_24h >= 3 ? 'critical' : 'warning',
      message: `${w.workflow_name}: ${w.failures_24h} failures in last 24h`
    });
  });
}

// Check for stale workflows (no run in 48h)
const now = new Date();
const staleWorkflows = workflowHealth.filter(w => {
  if (!w.last_run) return true;
  const lastRun = new Date(w.last_run);
  return (now - lastRun) > 48 * 60 * 60 * 1000;
});

if (staleWorkflows.length > 0) {
  if (overallStatus === 'healthy') overallStatus = 'warning';
  staleWorkflows.forEach(w => {
    issues.push({
      type: 'stale_workflow',
      severity: 'warning',
      message: `${w.workflow_name}: No run in 48+ hours`
    });
  });
}

// Check data freshness
if (dataHealth.traffic_data === 0) {
  overallStatus = 'degraded';
  issues.push({
    type: 'missing_data',
    severity: 'critical',
    message: 'No traffic data collected yesterday'
  });
}

if (dataHealth.ranking_data === 0) {
  if (overallStatus === 'healthy') overallStatus = 'warning';
  issues.push({
    type: 'missing_data',
    severity: 'warning',
    message: 'No ranking data collected yesterday'
  });
}

return [{
  json: {
    overall_status: overallStatus,
    issues,
    issue_count: issues.length,
    critical_count: issues.filter(i => i.severity === 'critical').length,
    workflow_count: workflowHealth.length,
    data_health: dataHealth,
    checked_at: new Date().toISOString()
  }
}];
